function DrawTable() {
  const { Table } = components;
  const columns =
    data.length > 0
      ? Object.keys(data[0]).map((key) => ({
          title: key.replace(/_/g, " "),
          dataIndex: key,
          key
        }))
      : [];
  return (
    <div>
      <Table
        columns={columns}
        dataSource={data}
        rowKey={(record, index) => index}
        pagination={true}
      />
    </div>
  );
}
